CREATE TABLE cons(constituentid BIGINT, uuid VARCHAR, ulanid DOUBLE, preferreddisplayname VARCHAR, forwarddisplayname VARCHAR, lastname VARCHAR, displaydate VARCHAR, artistofngaobject BIGINT, beginyear DOUBLE, endyear DOUBLE, visualbrowsertimespan VARCHAR, nationality VARCHAR, visualbrowsernationality VARCHAR, constituenttype VARCHAR, wikidataid VARCHAR);;
CREATE TABLE media(mediaid BIGINT, mediatype VARCHAR, title VARCHAR, description VARCHAR, duration DOUBLE, "language" VARCHAR, thumbnailurl VARCHAR, playurl VARCHAR, downloadurl VARCHAR, keywords VARCHAR, tags VARCHAR, imageurl VARCHAR, presentationdate VARCHAR, releasedate VARCHAR, lastmodified VARCHAR);;
CREATE TABLE media_relationships(mediaid BIGINT, relatedid BIGINT, relatedentity VARCHAR);;
CREATE TABLE objects(objectid BIGINT, uuid VARCHAR, accessioned BIGINT, accessionnum VARCHAR, title VARCHAR, displaydate VARCHAR, beginyear DOUBLE, endyear DOUBLE, visualbrowsertimespan VARCHAR, medium VARCHAR, dimensions VARCHAR, attributioninverted VARCHAR, attribution VARCHAR, creditline VARCHAR, classification VARCHAR, visualbrowserclassification VARCHAR, isvirtual BIGINT, departmentabbr VARCHAR, lastdetectedmodification VARCHAR, wikidataid VARCHAR);;
CREATE TABLE objects_cons(objectid BIGINT, uuid VARCHAR, accessioned BIGINT, accessionnum VARCHAR, title VARCHAR, displaydate VARCHAR, beginyear DOUBLE, endyear DOUBLE, visualbrowsertimespan VARCHAR, medium VARCHAR, dimensions VARCHAR, attributioninverted VARCHAR, attribution VARCHAR, creditline VARCHAR, classification VARCHAR, visualbrowserclassification VARCHAR, isvirtual BIGINT, departmentabbr VARCHAR, lastdetectedmodification VARCHAR, wikidataid VARCHAR);;
CREATE TABLE text_entries(objectid BIGINT, "text" VARCHAR, texttype VARCHAR, "year" DOUBLE);;

